Infraestrutura como codigo para custom-images - DataFlow Solutions - data-lake-modernization:

**main.tf:**
```hcl
terraform {
  required_providers {
    oci = {
      source  = "oracle/oci"
      version = "~> 5.0"
    }
  }
}

provider "oci" {
  region = "us-ashburn-1"
}

resource "oci_core_image" "main" {
  compartment_id = var.compartment_ocid
  display_name   = "custom-images-development-021"

  # Configuracao especifica
  shape          = "BM.Standard.E5"

  tags = {
    project     = "DataFlow Solutions - data-lake-modernization"
    environment = "development"
    managed_by  = "terraform"
  }
}

variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment development"
}

output "resource_id" {
  value = oci_core_image.main.id
}
```

**variables.tf:**
```hcl
variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment"
}

variable "region" {
  type        = string
  default     = "us-ashburn-1"
  description = "Regiao OCI"
}
```

**Deploy:**
```bash
terraform init
terraform plan -var="compartment_ocid=<ocid>"
terraform apply -var="compartment_ocid=<ocid>" -auto-approve
```

**Configuracao:**
- Compartment: `development`
- Region: `us-ashburn-1`
- Shape: `BM.Standard.E5`
- OCPUs: `32`
- Storage: `500 GB`

Documentacao: https://docs.oracle.com/en-us/iaas/Content/Compute/Tasks/managingcustomimages.htm

